        perror("Erreur dans le pipe");
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        perror("Erreur dans le fork");
        return 1;
    }

    if (pid == 0) { // Code du processus fils
        close(fd[1]); // Fermer l'écriture
        dup2(fd[0], STDIN_FILENO); // Rediriger l'entrée
        close(fd[0]); // Fermer le pipe non nécessaire
        execlp("votre_programme", "votre_programme", NULL);
        perror("Erreur dans execlp");
        return 1;
