    std::string input;
    std::getline(std::cin, input);
    write(fd[1], input.c_str(), input.size() + 1); // Écrire dans le pipe
    close(fd[1]); // Fermer l'écriture
    wait(NULL); // Attendre que le processus fils termine
    return 0;
}
